class Solution {
public:
    int getKth(int lo, int hi, int k) {
        vector<pair<int, int>> powers(hi - lo + 1);
        for (int i = lo; i <= hi; ++i) {
            powers[i - lo] = {i, calculatePower(i)};
        }
        sort(powers.begin(), powers.end(), [](const auto& a, const auto& b) {
            if (a.second == b.second) {
                return a.first < b.first;
            }
            return a.second < b.second;
        });
        return powers[k - 1].first;
    }
    int calculatePower(int x) {
        int power = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            ++power;
        }
        return power;
    }
};
